import { NextResponse } from "next/server";

export async function POST() {
  // TODO: Implement the Liveblocks access-token authentication endpoint.
  // The executor must:
  //   * Parse `room`, `userId`, and `role` from the JSON request body.
  //   * Reject malformed requests (missing fields or invalid role)
  //     with HTTP 400 and { error: string }.
  //   * Start a Liveblocks session, grant the requested room either
  //     read-only or full access based on the role, then authorize and
  //     return the upstream { status, body } verbatim.
  return NextResponse.json(
    { error: "Not implemented. Implement the Liveblocks access-token auth endpoint." },
    { status: 501 },
  );
}

"use client";

// TODO: Implement the real-time room UI.
// The executor must:
//   * Mount <LiveblocksProvider authEndpoint={...callback...}> with a callback
//     that POSTs { room, userId, role } to /api/liveblocks-auth.
//   * Mount <RoomProvider id={params.roomId} initialStorage={{ counter: 0 }}>.
//   * Render the connection status in an element with data-testid="connection-status".
//   * Render the counter value in an element with data-testid="counter-value".
//   * Render the user's role in an element with data-testid="role-label".
//   * Render an increment button with data-testid="increment-button" that
//     mutates Storage via useMutation; this button MUST be disabled when
//     the role is "viewer".

export default function RoomPageStub() {
  return (
    <main>
      <h1>Room page stub</h1>
      <p>Not implemented yet.</p>
      <span data-testid="connection-status">stub</span>
      <span data-testid="counter-value">stub</span>
      <span data-testid="role-label">stub</span>
      <button data-testid="increment-button" disabled>stub</button>
    </main>
  );
}

export default function HomePage() {
  return (
    <main>
      <h1>Liveblocks Read-Only Room Demo</h1>
      <p>
        Visit <code>/rooms/&lt;roomId&gt;?userId=&lt;id&gt;&amp;role=&lt;editor|viewer&gt;</code>
        to enter a room.
      </p>
    </main>
  );
}

import type { ReactNode } from "react";

export const metadata = {
  title: "Liveblocks Read-Only Room Demo",
};

export default function RootLayout({ children }: { children: ReactNode }) {
  return (
    <html lang="en">
      <body>{children}</body>
    </html>
  );
}

