          );

          // If the `threads` settings are changed, trigger a polling to update thread subscriptions
          if (settings.threads) {
            pollThreadsForRoomId(room.id);
          }
        },
        (err: Error) =>
          onMutationFailure(
            optimisticId,
            { type: "UPDATE_NOTIFICATION_SETTINGS_ERROR", roomId: room.id },
            err
